export default function SendMoneyFlow() {
  const [step, setStep] = React.useState<"pick"|"amount"|"review"|"done"|"pending">("pick");
  const [payees, setPayees] = React.useState<any[]>([]);
  const [selectedPayee, setSelectedPayee] = React.useState<any>(null);
  const [amount, setAmount] = React.useState("");
  const [memo, setMemo] = React.useState("");
  const [error, setError] = React.useState("");
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    tools.host_listPayees({}).then((res: any) => {
      setPayees(res.data || res.payees || res || []);
    });
  }, []);

  const amountCents = Math.round(parseFloat(amount || "0") * 100);

  function handlePickPayee(p: any) {
    setSelectedPayee(p);
    setStep("amount");
    setError("");
  }

  function handleAmountNext() {
    if (!amount || isNaN(parseFloat(amount)) || parseFloat(amount) <= 0) {
      setError("Please enter a valid amount.");
      return;
    }
    setError("");
    setStep("review");
  }

  async function handleSend() {
    setLoading(true);
    setError("");
    try {
      const res = await tools.host_transferMoney({
        amount: amountCents,
        recipient_name: selectedPayee.name || selectedPayee.label || selectedPayee.payeeName || "",
        memo: memo || ""
      });
      if (res && res.status === "pending-approval") {
        setStep("pending");
      } else {
        setStep("done");
      }
    } catch (e: any) {
      setError("Transfer failed. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  function reset() {
    setStep("pick");
    setSelectedPayee(null);
    setAmount("");
    setMemo("");
    setError("");
  }

  const containerStyle: React.CSSProperties = {
    maxWidth: 480,
    margin: "0 auto",
    padding: "32px 16px",
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
  };

  const surfaceStyle: React.CSSProperties = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-medium)",
    padding: "28px 24px",
  };

  const labelStyle: React.CSSProperties = {
    fontSize: 12,
    color: "var(--vendo-color-muted)",
    textTransform: "uppercase",
    letterSpacing: "0.06em",
    marginBottom: 12,
    fontWeight: 600,
  };

  const headingStyle: React.CSSProperties = {
    fontSize: 20,
    fontWeight: 700,
    marginBottom: 20,
    fontFamily: "var(--vendo-heading-family, var(--vendo-font-family))",
  };

  const inputStyle: React.CSSProperties = {
    width: "100%",
    padding: "10px 12px",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    fontSize: 15,
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
    background: "var(--vendo-color-surface)",
    boxSizing: "border-box",
    outline: "none",
  };

  const primaryBtn: React.CSSProperties = {
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    border: "none",
    borderRadius: "var(--vendo-radius-small)",
    padding: "11px 24px",
    fontSize: 15,
    fontWeight: 600,
    cursor: "pointer",
    width: "100%",
    marginTop: 8,
  };

  const ghostBtn: React.CSSProperties = {
    background: "transparent",
    color: "var(--vendo-color-muted)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    padding: "10px 24px",
    fontSize: 15,
    fontWeight: 500,
    cursor: "pointer",
    width: "100%",
    marginTop: 8,
  };

  const payeeRowStyle: React.CSSProperties = {
    display: "flex",
    alignItems: "center",
    gap: 12,
    padding: "12px 14px",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    cursor: "pointer",
    marginBottom: 8,
    background: "var(--vendo-color-surface)",
    transition: "border-color 0.15s",
  };

  const avatarStyle: React.CSSProperties = {
    width: 38,
    height: 38,
    borderRadius: "50%",
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: 700,
    fontSize: 15,
    flexShrink: 0,
  };

  const rowDetailStyle: React.CSSProperties = {
    display: "flex",
    flexDirection: "column",
    gap: 2,
  };

  const reviewRowStyle: React.CSSProperties = {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "10px 0",
    borderBottom: "1px solid var(--vendo-color-border)",
  };

  const reviewLabelStyle: React.CSSProperties = {
    fontSize: 13,
    color: "var(--vendo-color-muted)",
  };

  const reviewValueStyle: React.CSSProperties = {
    fontSize: 15,
    fontWeight: 500,
  };

  function getInitials(p: any) {
    const name = p.name || p.label || p.payeeName || "?";
    return name.split(" ").map((w: string) => w[0]).join("").slice(0, 2).toUpperCase();
  }

  function getPayeeName(p: any) {
    return p.name || p.label || p.payeeName || "Unknown";
  }

  function getPayeeDetail(p: any) {
    return p.accountNumber ? `···${String(p.accountNumber).slice(-4)}` : p.bank || p.email || p.type || "";
  }

  if (step === "done") {
    return (
      <div style={containerStyle}>
        <div style={surfaceStyle}>
          <div style={{ textAlign: "center", padding: "16px 0 8px" }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>✓</div>
            <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 8 }}>Transfer sent</div>
            <div style={{ color: "var(--vendo-color-muted)", fontSize: 15, marginBottom: 4 }}>
              {fmt.money(amountCents)} to {getPayeeName(selectedPayee)}
            </div>
            {memo ? <div style={{ color: "var(--vendo-color-muted)", fontSize: 13, marginTop: 4 }}>"{memo}"</div> : null}
            <button style={{ ...primaryBtn, marginTop: 28 }} onClick={reset}>Send another</button>
          </div>
        </div>
      </div>
    );
  }

  if (step === "pending") {
    return (
      <div style={containerStyle}>
        <div style={surfaceStyle}>
          <div style={{ textAlign: "center", padding: "16px 0 8px" }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>⏳</div>
            <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 8 }}>Awaiting approval</div>
            <div style={{ color: "var(--vendo-color-muted)", fontSize: 15, marginBottom: 4 }}>
              Your transfer of {fmt.money(amountCents)} to {getPayeeName(selectedPayee)} is pending approval.
            </div>
            <button style={{ ...primaryBtn, marginTop: 28 }} onClick={reset}>Send another</button>
          </div>
        </div>
      </div>
    );
  }

  if (step === "review") {
    return (
      <div style={containerStyle}>
        <div style={surfaceStyle}>
          <div style={headingStyle}>Review transfer</div>
          <div style={reviewRowStyle}>
            <span style={reviewLabelStyle}>To</span>
            <span style={reviewValueStyle}>{getPayeeName(selectedPayee)}</span>
          </div>
          <div style={reviewRowStyle}>
            <span style={reviewLabelStyle}>From</span>
            <span style={reviewValueStyle}>Checking</span>
          </div>
          <div style={reviewRowStyle}>
            <span style={reviewLabelStyle}>Amount</span>
            <span style={{ ...reviewValueStyle, fontSize: 20, fontWeight: 700 }}>{fmt.money(amountCents)}</span>
          </div>
          {memo ? (
            <div style={reviewRowStyle}>
              <span style={reviewLabelStyle}>Note</span>
              <span style={reviewValueStyle}>{memo}</span>
            </div>
          ) : null}
          {error ? <div style={{ color: "var(--vendo-color-danger)", fontSize: 13, marginTop: 12 }}>{error}</div> : null}
          <button style={{ ...primaryBtn, marginTop: 20, opacity: loading ? 0.6 : 1 }} onClick={handleSend} disabled={loading}>
            {loading ? "Sending…" : "Confirm & send"}
          </button>
          <button style={ghostBtn} onClick={() => setStep("amount")}>Back</button>
        </div>
      </div>
    );
  }

  if (step === "amount") {
    return (
      <div style={containerStyle}>
        <div style={surfaceStyle}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 24 }}>
            <div style={avatarStyle}>{getInitials(selectedPayee)}</div>
            <div>
              <div style={{ fontWeight: 600, fontSize: 16 }}>{getPayeeName(selectedPayee)}</div>
              <div style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>{getPayeeDetail(selectedPayee)}</div>
            </div>
          </div>
          <div style={headingStyle}>How much?</div>
          <div style={{ marginBottom: 16 }}>
            <div style={labelStyle}>Amount (USD)</div>
            <input
              style={{ ...inputStyle, fontSize: 28, fontWeight: 700, padding: "12px 14px" }}
              type="number"
              min="0.01"
              step="0.01"
              placeholder="0.00"
              value={amount}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setAmount(e.target.value)}
            />
          </div>
          <div style={{ marginBottom: 8 }}>
            <div style={labelStyle}>Note (optional)</div>
            <input
              style={inputStyle}
              type="text"
              placeholder="What's it for?"
              value={memo}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setMemo(e.target.value)}
            />
          </div>
          {error ? <div style={{ color: "var(--vendo-color-danger)", fontSize: 13, marginTop: 8 }}>{error}</div> : null}
          <button style={{ ...primaryBtn, marginTop: 20 }} onClick={handleAmountNext}>Continue</button>
          <button style={ghostBtn} onClick={() => setStep("pick")}>Back</button>
        </div>
      </div>
    );
  }

  return (
    <div style={containerStyle}>
      <div style={surfaceStyle}>
        <div style={headingStyle}>Send money</div>
        <div style={labelStyle}>Choose a payee</div>
        {payees.length === 0 ? (
          <div style={{ color: "var(--vendo-color-muted)", fontSize: 15, padding: "16px 0" }}>No saved payees found.</div>
        ) : (
          payees.map((p: any, i: number) => (
            <div
              key={p.id || i}
              style={payeeRowStyle}
              onClick={() => handlePickPayee(p)}
              onMouseEnter={(e: React.MouseEvent<HTMLDivElement>) => (e.currentTarget.style.borderColor = "var(--vendo-color-accent)")}
              onMouseLeave={(e: React.MouseEvent<HTMLDivElement>) => (e.currentTarget.style.borderColor = "var(--vendo-color-border)")}
            >
              <div style={avatarStyle}>{getInitials(p)}</div>
              <div style={rowDetailStyle}>
                <span style={{ fontWeight: 600, fontSize: 15 }}>{getPayeeName(p)}</span>
                <span style={{ fontSize: 13, color: "var(--vendo-color-muted)" }}>{getPayeeDetail(p)}</span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
